func CreateStaticCredentialUsernamePasswordCli(t testing.TB, ctx context.Context, credentialStoreId string, user string, password string) (string, error) {
n1: 	name, err := base62.Random(16)
n2: 	if err != nil {
n3: 		return "", err
	}

n4: 	output := e2e.RunCommand(ctx, "boundary",
		e2e.WithArgs(
			"credentials", "create", "username-password",
			"-credential-store-id", credentialStoreId,
			"-username", user,
			"-password", "env://E2E_CREDENTIALS_PASSWORD",
			"-name", fmt.Sprintf("e2e Credential %s", name),
			"-description", "e2e",
			"-format", "json",
		),
		e2e.WithEnv("E2E_CREDENTIALS_PASSWORD", password),
	)
n5: 	if output.Err != nil {
n6: 		return "", fmt.Errorf("%w: %s", output.Err, string(output.Stderr))
	}

n7: 	var createCredentialsResult credentials.CredentialCreateResult
n8: 	err = json.Unmarshal(output.Stdout, &createCredentialsResult)
n9: 	if err != nil {
n10: 		return "", err
	}

n11: 	credentialId := createCredentialsResult.Item.Id
n12: 	t.Logf("Created Username/Password Credentials: %s", credentialId)
n13: 	return credentialId, nil
}
